package main

import (
	"database/sql"
	"encoding/json"
	"fmt"
	"log"
	"net/http"
)

func searchUsers(w http.ResponseWriter, r *http.Request) {
	// Get the username from the query parameter
	username := r.URL.Query().Get("username")

	// Connect to the PostgreSQL database
	db, err := sql.Open("postgres", "user=<username> password=<password> host=<host> port=5432 dbname=<database> sslmode=disable")
	if err != nil {
		log.Fatal(err)
	}
	defer db.Close()

	// Prepare the SQL query
	query := "SELECT * FROM users WHERE username = $1"

	// Execute the query and get the results
	rows, err := db.Query(query, username)
	if err != nil {
		log.Fatal(err)
	}
	defer rows.Close()

	// Create a slice to store the users
	var users []User

	// Iterate over the results and add them to the slice
	for rows.Next() {
		var user User
		if err := rows.Scan(&user.ID, &user.Username, &user.Email); err != nil {
			log.Fatal(err)
		}
		users = append(users, user)
	}

	// Marshal the users to JSON and write them to the response
	json.NewEncoder(w).Encode(users)
}

type User struct {
	ID       int    `json:"id"`
	Username string `json:"username"`
	Email    string `json:"email"`
}

func main() {
	http.HandleFunc("/search", searchUsers)
	log.Fatal(http.ListenAndServe(":8080", nil))
}